// Pure data + server-safe helpers for the 従業員セルフサービス 書類ダウンロード screen.
// No "use client", no function props — safe to import from a Server Component.

export type DocCategory =
  | "payslip" // 給与明細
  | "bonus" // 賞与明細
  | "withholding" // 源泉徴収票
  | "certificate" // 証明書
  | "application"; // 申請書

export type FileType = "pdf" | "csv";

export interface HrDocument {
  id: string;
  category: DocCategory;
  /** Grouping key — 年 (西暦). */
  year: number;
  /** 書類名 e.g. 2026年6月分 給与明細 */
  name: string;
  fileType: FileType;
  /** バイト数（meta 表示用に整形する）。 */
  sizeBytes: number;
  /** 発行日 ISO (YYYY-MM-DD)。 */
  issuedOn: string;
  /** 新着（未開封）バッジ。 */
  isNew?: boolean;
}

/** 証明書の発行申請メニュー行。 */
export interface IssuanceItem {
  id: string;
  name: string; // 在職証明書 など
  description: string; // 用途や様式の説明
  /** 即時発行 か、○営業日 か。 */
  lead: { kind: "instant" } | { kind: "businessDays"; days: number };
}

export const CATEGORY_LABELS: Record<DocCategory, string> = {
  payslip: "給与明細",
  bonus: "賞与明細",
  withholding: "源泉徴収票",
  certificate: "証明書",
  application: "申請書",
};

/** 整形ヘルパー（サーバーでも呼べる純関数）。 */
export function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes}B`;
  const kb = bytes / 1024;
  if (kb < 1024) return `${Math.round(kb)}KB`;
  const mb = kb / 1024;
  return `${mb.toFixed(1).replace(/\.0$/, "")}MB`;
}

/** 2026-06-25 → 2026/06/25 */
export function formatIssuedDate(iso: string): string {
  return iso.replaceAll("-", "/");
}

export function issuanceLeadLabel(item: IssuanceItem): string {
  return item.lead.kind === "instant"
    ? "即時発行"
    : `発行に約${item.lead.days}営業日`;
}

