"use client";

// DocumentRow — the downloadable 書類 row.
//
// HAND-ROLLED. @gunjo/ui has no DocumentRow / FileDownloadRow / AttachmentRow primitive.
// The closest kit primitives are:
//   - ListCard: leading/title/description/meta/trailing — but its `onSelect` makes the WHOLE
//     card a button (aria-pressed). A document row needs THREE independent hit targets:
//     a bulk-select checkbox, a tap-to-preview surface, and a download button. Nesting a
//     <button> (download) inside ListCard's <button> (onSelect) is invalid HTML, so ListCard
//     can't host this row as designed.
//   - FileTree: a disclosure tree, wrong shape.
//   - FileUploader: the opposite direction (upload).
// So this composes kit atoms (Checkbox, Icon, Badge, Button) into the missing row.

import * as React from "react";
import { Checkbox, Icon, Badge, Button } from "@gunjo/ui";
import {
  IconFileTypePdf,
  IconFileTypeCsv,
  IconDownload,
} from "@tabler/icons-react";
import {
  type HrDocument,
  formatFileSize,
  formatIssuedDate,
} from "./data";

const FILE_ICON = {
  pdf: IconFileTypePdf,
  csv: IconFileTypeCsv,
} as const;

const FILE_LABEL = {
  pdf: "PDF",
  csv: "CSV",
} as const;

export interface DocumentRowProps {
  doc: HrDocument;
  selected: boolean;
  onToggleSelect: (id: string) => void;
  onDownload: (doc: HrDocument) => void;
}

export function DocumentRow({
  doc,
  selected,
  onToggleSelect,
  onDownload,
}: DocumentRowProps) {
  const meta = `${FILE_LABEL[doc.fileType]}・${formatFileSize(
    doc.sizeBytes,
  )}・発行日 ${formatIssuedDate(doc.issuedOn)}`;

  return (
    <div
      className="flex items-center gap-3 border-b border-border px-3 py-2.5 last:border-b-0 data-[selected=true]:bg-accent/40"
      data-selected={selected}
    >
      {/* 一括選択 */}
      <Checkbox
        checked={selected}
        onCheckedChange={() => onToggleSelect(doc.id)}
        aria-label={`${doc.name} を選択`}
        className="shrink-0"
      />

      {/* file-type アイコン */}
      <span
        className="flex size-9 shrink-0 items-center justify-center rounded-md bg-muted text-muted-foreground"
        aria-hidden="true"
      >
        <Icon icon={FILE_ICON[doc.fileType]} size="md" />
      </span>

      {/* 書類名 + meta */}
      <div className="min-w-0 flex-1">
        <div className="flex items-center gap-2">
          <span className="truncate text-sm font-medium text-foreground">
            {doc.name}
          </span>
          {doc.isNew ? (
            <Badge variant="info" className="shrink-0">
              新着
            </Badge>
          ) : null}
        </div>
        <p className="mt-0.5 truncate text-xs tabular-nums text-muted-foreground">
          {meta}
        </p>
      </div>

      {/* ダウンロード（独立した hit target / ≥44px） */}
      <Button
        variant="outline"
        size="icon"
        className="size-11 shrink-0 sm:size-9"
        onClick={() => onDownload(doc)}
        aria-label={`${doc.name} をダウンロード（${FILE_LABEL[doc.fileType]}・${formatFileSize(doc.sizeBytes)}）`}
      >
        <Icon icon={IconDownload} size="sm" />
      </Button>
    </div>
  );
}

"use client";

import * as React from "react";
import {
  PageHeader,
  SectionList,
  type SectionListSection,
  FilterChips,
  NavRow,
  SettingGroup,
  Badge,
  Button,
  Switch,
  Checkbox,
  Icon,
  Separator,
  EmptyState,
  BottomActionBar,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  useToast,
} from "@gunjo/ui";
import {
  IconCertificate2,
  IconFileText,
  IconBuildingBank,
  IconReceiptYen,
  IconUserCheck,
  IconFileInvoice,
  IconDownload,
  IconClock,
  IconCircleCheck,
  IconShieldLock,
  IconBell,
  IconMailForward,
} from "@tabler/icons-react";
import { DocumentRow } from "./DocumentRow";
import {
  documents,
  issuanceItems,
  applicationForms,
  employee,
  CATEGORY_LABELS,
  issuanceLeadLabel,
  type DocCategory,
  type HrDocument,
  type IssuanceItem,
} from "./data";

type CategoryFilter = "all" | DocCategory;

const ISSUANCE_ICON: Record<string, typeof IconCertificate2> = {
  "iss-employment": IconUserCheck,
  "iss-salary": IconReceiptYen,
  "iss-income": IconBuildingBank,
  "iss-work": IconCertificate2,
  "iss-retirement": IconFileText,
};

export function HrDocumentsClient() {
  const { showToast } = useToast();

  // ── カテゴリ絞り込み ──────────────────────────────
  const [category, setCategory] = React.useState<CategoryFilter>("all");

  // ── 一括選択 ─────────────────────────────────────
  const [selectedIds, setSelectedIds] = React.useState<Set<string>>(new Set());

  // ── 電子交付 ─────────────────────────────────────
  const [eDelivery, setEDelivery] = React.useState(true);
  const [eDeliveryNotify, setEDeliveryNotify] = React.useState(true);

  // ── 発行申請ダイアログ ────────────────────────────
  const [issuance, setIssuance] = React.useState<IssuanceItem | null>(null);

  const visibleDocs = React.useMemo(
    () =>
      category === "all"
        ? documents
        : documents.filter((d) => d.category === category),
    [category],
  );

  // カテゴリ別件数（chip の count 用）
  const counts = React.useMemo(() => {
    const c: Record<string, number> = { all: documents.length };
    for (const d of documents) c[d.category] = (c[d.category] ?? 0) + 1;
    return c;
  }, []);

  const toggleSelect = React.useCallback((id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  const downloadOne = React.useCallback(
    (doc: HrDocument) => {
      showToast(`「${doc.name}」をダウンロードしました`, "success");
    },
    [showToast],
  );

  const downloadSelected = React.useCallback(() => {
    const n = selectedIds.size;
    if (n === 0) return;
    showToast(`選択した ${n} 件の書類をダウンロードしました`, "success");
    setSelectedIds(new Set());
  }, [selectedIds, showToast]);

  // 現在表示中の書類を「年」でグループ化 → SectionList の sections に変換
  const sections: SectionListSection[] = React.useMemo(() => {
    const byYear = new Map<number, HrDocument[]>();
    for (const d of visibleDocs) {
      const arr = byYear.get(d.year) ?? [];
      arr.push(d);
      byYear.set(d.year, arr);
    }
    const years = [...byYear.keys()].sort((a, b) => b - a);

    return years.map((year) => {
      const docs = byYear.get(year)!;
      const selectedInGroup = docs.filter((d) => selectedIds.has(d.id)).length;
      const allSelected = selectedInGroup === docs.length;

      const toggleGroup = () => {
        setSelectedIds((prev) => {
          const next = new Set(prev);
          if (allSelected) docs.forEach((d) => next.delete(d.id));
          else docs.forEach((d) => next.add(d.id));
          return next;
        });
      };

      return {
        key: year,
        title: `${year}年`,
        sublabel: `${docs.length}件`,
        meta: (
          <button
            type="button"
            onClick={toggleGroup}
            className="rounded text-xs font-medium text-foreground underline-offset-2 hover:underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            aria-label={
              allSelected
                ? `${year}年の書類の選択をすべて解除`
                : `${year}年の書類をすべて選択`
            }
          >
            {allSelected ? "選択解除" : "すべて選択"}
          </button>
        ),
        content: (
          <div className="overflow-hidden rounded-lg border border-border bg-card">
            {docs.map((doc) => (
              <DocumentRow
                key={doc.id}
                doc={doc}
                selected={selectedIds.has(doc.id)}
                onToggleSelect={toggleSelect}
                onDownload={downloadOne}
              />
            ))}
          </div>
        ),
      };
    });
  }, [visibleDocs, selectedIds, toggleSelect, downloadOne]);

  const categoryChips = React.useMemo(
    () => [
      { value: "all", label: "すべて", count: counts.all },
      ...(Object.keys(CATEGORY_LABELS) as DocCategory[]).map((cat) => ({
        value: cat,
        label: CATEGORY_LABELS[cat],
        count: counts[cat] ?? 0,
        disabled: (counts[cat] ?? 0) === 0,
      })),
    ],
    [counts],
  );

  const selectedCount = selectedIds.size;
  // 証明書/申請書カテゴリでは書類一覧（ダウンロード対象）は出さない
  const showDownloadList = category !== "certificate" && category !== "application";
  const showIssuance = category === "all" || category === "certificate";
  const showForms = category === "all" || category === "application";

  return (
    <div className="flex min-h-dvh flex-col bg-background pb-28">
      <PageHeader
        title="書類ダウンロード"
        subtitle="給与・証明書セルフサービス"
        actions={
          <Badge variant="outline" icon={<Icon icon={IconShieldLock} size="xs" />}>
            本人認証済み
          </Badge>
        }
      />

      <main className="mx-auto w-full max-w-2xl flex-1 px-4 py-4">
        {/* 社員サマリ */}
        <section
          aria-label="社員情報"
          className="mb-4 rounded-lg border border-border bg-card p-4"
        >
          <div className="flex items-center justify-between gap-3">
            <div className="min-w-0">
              <p className="text-base font-semibold text-foreground">
                {employee.name}
              </p>
              <p className="truncate text-xs text-muted-foreground">
                社員番号 {employee.employeeNo}・{employee.department}
              </p>
            </div>
            <Badge
              variant="success"
              icon={<Icon icon={IconCircleCheck} size="xs" />}
            >
              在籍中
            </Badge>
          </div>
        </section>

        {/* カテゴリ絞り込み */}
        <div className="mb-4">
          <FilterChips
            items={categoryChips}
            value={category}
            onValueChange={(v) => setCategory(v as CategoryFilter)}
            aria-label="書類カテゴリの絞り込み"
          />
        </div>

        {/* ダウンロードできる書類（年でグループ化） */}
        {showDownloadList ? (
          <section aria-label="ダウンロードできる書類" className="mb-6">
            {sections.length > 0 ? (
              <SectionList sections={sections} label="ダウンロードできる書類" />
            ) : (
              <EmptyState
                icon={<Icon icon={IconFileText} size="xl" />}
                title="該当する書類はありません"
                description="別のカテゴリを選ぶか、電子交付の設定をご確認ください。"
              />
            )}
          </section>
        ) : null}

        {/* 証明書の発行申請 */}
        {showIssuance ? (
          <section aria-label="証明書の発行申請" className="mb-6">
            <SettingGroup label="証明書の発行申請">
              {issuanceItems.map((item) => (
                <NavRow
                  key={item.id}
                  icon={
                    <Icon
                      icon={ISSUANCE_ICON[item.id] ?? IconCertificate2}
                      size="sm"
                    />
                  }
                  label={item.name}
                  description={item.description}
                  value={
                    <span className="inline-flex items-center gap-1">
                      <Icon
                        icon={item.lead.kind === "instant" ? IconCircleCheck : IconClock}
                        size="xs"
                        className={
                          item.lead.kind === "instant"
                            ? "text-success-strong"
                            : undefined
                        }
                      />
                      {issuanceLeadLabel(item)}
                    </span>
                  }
                  opensDialog
                  onSelect={() => setIssuance(item)}
                />
              ))}
            </SettingGroup>
          </section>
        ) : null}

        {/* 各種申請書（即時ダウンロード様式） */}
        {showForms ? (
          <section aria-label="各種申請書" className="mb-6">
            <SettingGroup label="各種申請書（様式ダウンロード）">
              {applicationForms.map((form) => (
                <NavRow
                  key={form.id}
                  icon={<Icon icon={IconFileInvoice} size="sm" />}
                  label={form.name}
                  description={form.description}
                  trailing={
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() =>
                        showToast(`「${form.name}」をダウンロードしました`, "success")
                      }
                      aria-label={`${form.name} の様式をダウンロード`}
                    >
                      <Icon icon={IconDownload} size="sm" />
                      <span>様式DL</span>
                    </Button>
                  }
                />
              ))}
            </SettingGroup>
          </section>
        ) : null}

        {/* 電子交付の設定 */}
        <section aria-label="電子交付の設定">
          <SettingGroup label="電子交付の設定">
            <NavRow
              icon={<Icon icon={IconMailForward} size="sm" />}
              label="給与明細を電子交付で受け取る"
              description="紙の郵送を停止し、PDFをこの画面で受け取ります"
              trailing={
                <Switch
                  checked={eDelivery}
                  onCheckedChange={setEDelivery}
                  aria-label="給与明細を電子交付で受け取る"
                />
              }
            />
            <NavRow
              icon={<Icon icon={IconBell} size="sm" />}
              label="新しい書類の通知"
              description="発行時にメール・アプリで通知します"
              trailing={
                <Switch
                  checked={eDeliveryNotify}
                  onCheckedChange={setEDeliveryNotify}
                  disabled={!eDelivery}
                  aria-label="新しい書類の通知"
                />
              }
            />
          </SettingGroup>
          <p className="mt-2 px-1 text-xs text-muted-foreground">
            電子交付には電子交付規程への同意が必要です。マイナンバーを含む書類は本人認証後のみ表示されます。
          </p>
        </section>
      </main>

      {/* 一括ダウンロード（選択時のみ表示） */}
      {selectedCount > 0 ? (
        <BottomActionBar
          maxWidth="xl"
          actions={
            <>
              <Button
                variant="ghost"
                onClick={() => setSelectedIds(new Set())}
              >
                選択解除
              </Button>
              <Button variant="default" onClick={downloadSelected}>
                <Icon icon={IconDownload} size="sm" />
                まとめてDL
              </Button>
            </>
          }
        >
          <div className="flex items-center gap-2">
            <Badge variant="default">{selectedCount}</Badge>
            <span className="text-sm text-foreground">件の書類を選択中</span>
          </div>
        </BottomActionBar>
      ) : null}

      {/* 発行申請の確認ダイアログ */}
      <IssuanceDialog
        item={issuance}
        onClose={() => setIssuance(null)}
        onSubmit={(item) => {
          setIssuance(null);
          showToast(`「${item.name}」の発行を申請しました`, "success");
        }}
      />
    </div>
  );
}

function IssuanceDialog({
  item,
  onClose,
  onSubmit,
}: {
  item: IssuanceItem | null;
  onClose: () => void;
  onSubmit: (item: IssuanceItem) => void;
}) {
  const [agreed, setAgreed] = React.useState(false);
  React.useEffect(() => {
    if (item) setAgreed(false);
  }, [item]);

  return (
    <Dialog
      open={item != null}
      onOpenChange={(open) => {
        if (!open) onClose();
      }}
    >
      <DialogContent closeLabel="閉じる">
        {item ? (
          <>
            <DialogHeader>
              <DialogTitle>{item.name} の発行申請</DialogTitle>
              <DialogDescription>{item.description}</DialogDescription>
            </DialogHeader>

            <div className="space-y-4">
              <div className="rounded-lg border border-border bg-muted/40 p-3 text-sm">
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">交付までの目安</span>
                  <span className="inline-flex items-center gap-1 font-medium text-foreground">
                    <Icon
                      icon={
                        item.lead.kind === "instant" ? IconCircleCheck : IconClock
                      }
                      size="xs"
                    />
                    {issuanceLeadLabel(item)}
                  </span>
                </div>
                <Separator className="my-2" />
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">受け取り方法</span>
                  <span className="font-medium text-foreground">
                    電子交付（PDF）
                  </span>
                </div>
              </div>
              <Checkbox
                checked={agreed}
                onCheckedChange={setAgreed}
                label="証明書の電子交付に同意します"
                description="記載内容（氏名・所属・支給額など）を会社が証明書として発行することに同意します。"
              />
            </div>

            <DialogFooter>
              <Button variant="outline" onClick={onClose}>
                キャンセル
              </Button>
              <Button
                variant="default"
                disabled={!agreed}
                onClick={() => onSubmit(item)}
              >
                発行を申請する
              </Button>
            </DialogFooter>
          </>
        ) : null}
      </DialogContent>
    </Dialog>
  );
}
